export function projectLocation(lat, lng) {
  const latitude = Math.max(-90, Math.min(90, Number(lat)));
  const longitude = Math.max(-180, Math.min(180, Number(lng)));
  return {
    x: 10 + ((longitude + 180) / 360) * 300,
    y: 8 + ((90 - latitude) / 180) * 134
  };
}
